async (page) => {
  const gamePage = page.context().pages()[1];

  // Equip Bronze Axe from slot 0
  // Step 1: Open inventory
  await gamePage.evaluate(() => document.getElementById('inventory-button').click());
  await gamePage.waitForTimeout(800);

  // Step 2: Click item slot 0
  await gamePage.evaluate((idx) => {
    const slots = document.querySelectorAll('.item-slot');
    if (slots[idx]) slots[idx].click();
  }, 0);
  await gamePage.waitForTimeout(800);

  // Step 3: Click equip button
  await gamePage.evaluate(() => {
    const btn = document.querySelector('.action-equip');
    if (btn) btn.click();
  });
  await gamePage.waitForTimeout(500);

  // Step 4: Close inventory
  await gamePage.evaluate(() => document.getElementById('inventory-button').click());
  await gamePage.waitForTimeout(500);

  await gamePage.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await gamePage.evaluate(() => JSON.stringify(window.__latestGameState));
  return state;
}

async (page) => {
  const gamePage = page.context().pages()[1];

  // Click on the Rat (click_x=592, estimate y from screenshot ~380)
  await gamePage.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 592, y: 380 });
  await gamePage.waitForTimeout(5000);

  await gamePage.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await gamePage.evaluate(() => {
    const gs = window.__latestGameState;
    if (!gs) return null;
    return {
      player_position: gs.player_position,
      player_stats: gs.player_stats,
      last_xp_event: gs.last_xp_event,
      last_combat: gs.last_combat,
      nearest_mob: gs.nearest_mob ? { name: gs.nearest_mob.name, distance: gs.nearest_mob.distance, click_x: gs.nearest_mob.click_x, click_y: gs.nearest_mob.click_y } : null,
      inventory: gs.inventory
    };
  });
  return JSON.stringify(state);
}
